# OPTIMIZED: Precompute values before loop
def execute(filters=None):
    item_list = get_items(filters)
    itemised_tax, tax_columns = get_tax_accounts(item_list)

    # FIX: Precompute scrubbed field names ONCE
    scrubbed_tax_fields = {}
    for tax in tax_columns:
        scrubbed_tax_fields.update({
            tax + " Rate": frappe.scrub(tax + " Rate"),
            tax + " Amount": frappe.scrub(tax + " Amount"),
        })

    for d in item_list:
        total_tax = 0

        for tax, details in itemised_tax.get(d.name, {}).items():
            row.update({
                # Use precomputed values - dictionary lookup instead of function call
                scrubbed_tax_fields[tax + " Rate"]: details.get("tax_rate", 0),
                scrubbed_tax_fields[tax + " Amount"]: details.get("tax_amount", 0),
            })
            total_tax += flt(details.get("tax_amount"))
